import{c as t,Q as o,j as r,m as i}from"./chunks/framework.CdiUUa3G.js";const u=JSON.parse('{"title":"PRD-019 · Immersive Mode — WebXR AR (Android web + wrapped) + ARKit (iPhone wrapped)","description":"","frontmatter":{},"headers":[],"relativePath":"prd/PRD-019.md","filePath":"prd/PRD-019.md"}'),s={name:"prd/PRD-019.md"};function a(n,e,d,l,c,p){return o(),r("div",null,[...e[0]||(e[0]=[i('<h1 id="prd-019-·-immersive-mode-—-webxr-ar-android-web-wrapped-arkit-iphone-wrapped" tabindex="-1">PRD-019 · Immersive Mode — WebXR AR (Android web + wrapped) + ARKit (iPhone wrapped) <a class="header-anchor" href="#prd-019-·-immersive-mode-—-webxr-ar-android-web-wrapped-arkit-iphone-wrapped" aria-label="Permalink to &quot;PRD-019 · Immersive Mode — WebXR AR (Android web + wrapped) + ARKit (iPhone wrapped)&quot;">​</a></h1><blockquote><p>Status · Draft v0.4 (all 4 v1 architectural decisions resolved 2026-05-16) Date · 2026-05-16 Owner · Marko Closes into · RFC-021 Slice gate · v1.x — last in the dependency chain (mobile + audio + sensory must ship first)</p></blockquote><blockquote><p><strong>Why this is a PRD.</strong> Immersive Mode is the editorial peak of the product: solar system on your kitchen table, planets singing from their physical positions, a Sagan-register narrator explaining what you&#39;re seeing. It depends on the four already-shipped pairs (mobile wrapper, audio narration, sensory layer, image pipeline) and adds two new architectural commitments: a Three.js whole-codebase upgrade (r128 → current, touching all 7 existing 3D scenes), and a Capacitor + ARKit Swift plugin for iPhone parity (the only path to AR on iPhone, since Apple has not shipped WebXR). The PRD framing evolves PRD-015&#39;s &quot;web is the product&quot; stance — the <strong>browser</strong> product stays web-only; the <strong>mobile app</strong> product is allowed to harness native power where it unlocks things the web can&#39;t do (ARKit being the canonical example).</p></blockquote><hr><h2 id="§why" tabindex="-1">§why <a class="header-anchor" href="#§why" aria-label="Permalink to &quot;§why&quot;">​</a></h2><p>The original orrery — the 18th-century brass instrument the product is named after — was a thing you held and turned with your hands. The whole product so far has been climbing back toward that tactile experience: 3D scenes you can orbit, planets that sing (PRD-017 sensory), a narrator that frames what you&#39;re looking at (PRD-016 audio). Immersive Mode is the moment it actually arrives — the solar system on a real table, in real space, with real spatial audio and a real voice in your ear.</p><p>This is the convergence feature. It does not introduce new content; it reframes everything already shipped through a different rendering target (AR camera passthrough), a different audio listener (XR camera), and a different default mode of attention (no UI chrome — narrator + planets + the room you&#39;re standing in).</p><p>It also unlocks a museum / classroom / projector deployment (&quot;Exhibit Mode&quot;) — same codebase, no AR, but auto-narrated cinematic orbits suitable for an unattended large-screen install. One app, three use modes: phone-in-hand AR, kitchen-table AR, museum-projector cinema.</p><hr><h2 id="§audiences" tabindex="-1">§audiences <a class="header-anchor" href="#§audiences" aria-label="Permalink to &quot;§audiences&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Audience</th><th>Why this lands the experience</th></tr></thead><tbody><tr><td>Curious learner (at home)</td><td>Pull out their Android phone or wrapped Orrery on iPhone, tap &quot;Enter AR&quot;, and walk around their solar system on the kitchen floor. Narrator guides them through. 10 minutes that they remember.</td></tr><tr><td>STEM student (classroom)</td><td>Teacher projects &quot;Exhibit Mode&quot; on a large screen; cinematic orbits + narrated tour run unattended. Students get phones and can scan a QR to take the same experience home.</td></tr><tr><td>Educator (museum / kiosk)</td><td>Exhibit Mode runs chrome-less on a kiosk monitor + speakers; visitors stop, listen, and a QR offers AR continuation on their own device.</td></tr><tr><td>Enthusiast (cinematic)</td><td>Wants the editorial peak — pale blue dot moment, Cernan&#39;s last words, the Kepler chord — delivered in the most immersive form available. AR + narrator + sonification + sensory haptics all firing.</td></tr></tbody></table><p>Note: <strong>iPhone Safari users do not get AR.</strong> They get the rest of the product (3D scenes + sensory + narration). AR is exclusive to (a) any Android Chrome (web or wrapped), and (b) iPhone in the wrapped Capacitor app via the ARKit Swift plugin.</p><hr><h2 id="§what-s-already-shipped-immersive-readiness-inventory" tabindex="-1">§what&#39;s already shipped (immersive-readiness inventory) <a class="header-anchor" href="#§what-s-already-shipped-immersive-readiness-inventory" aria-label="Permalink to &quot;§what&#39;s already shipped (immersive-readiness inventory)&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Capability</th><th>Status</th><th>Source</th></tr></thead><tbody><tr><td>11 primary nav routes (7 with 3D scenes)</td><td>shipped (v0.6)</td><td>TA.md</td></tr><tr><td>Capacitor mobile wrapper (Android-first, iPhone follows)</td><td>planned (PRD-015 / RFC-018, v0.8)</td><td>—</td></tr><tr><td>Audio narration episode system (PRD-016 Curator + Guide + Enthusiast)</td><td>planned (v0.9)</td><td>RFC-019</td></tr><tr><td>Sensory layer — gyro + sonification + haptics + audio-bus ducking</td><td>planned (v1.x)</td><td>PRD-017 / RFC-020</td></tr><tr><td>Image Pipeline v2 — vision scoring + smart-crop variants</td><td>planned (v1.x)</td><td>PRD-018 / RFC-022</td></tr><tr><td>Three.js r128 across 7 existing 3D scenes</td><td>shipped (v0.6)</td><td>TA.md §3D</td></tr><tr><td>ADR-057 (no localStorage; only <code>orrery_locale</code> cookie persists)</td><td>shipped</td><td>ADR-057</td></tr></tbody></table><p>What this means: Immersive Mode lands AFTER the entire stack above. It is <strong>last in the dependency chain.</strong> v1.x ship gate.</p><hr><h2 id="§architectural-axis-—-web-vs-mobile-app-split" tabindex="-1">§architectural axis — web vs mobile-app split <a class="header-anchor" href="#§architectural-axis-—-web-vs-mobile-app-split" aria-label="Permalink to &quot;§architectural axis — web vs mobile-app split&quot;">​</a></h2><p>Evolves PRD-015&#39;s framing. Made explicit because this is the first feature where the split actually matters:</p><table tabindex="0"><thead><tr><th>Surface</th><th>What it is</th><th>What it CAN do</th><th>What it CANNOT do</th></tr></thead><tbody><tr><td><strong>Web browser</strong> (<code>chipi.github.io</code>)</td><td>The web product. Mobile + desktop browser.</td><td>Web standards only. Three.js, Web Audio, Vibration API on Android, WebXR on Android Chrome.</td><td>No native APIs. iPhone Safari: no AR (WebKit lock).</td></tr><tr><td><strong>Capacitor mobile app</strong> (App Store + Play)</td><td>The wrapped app. Web shell + native plugins.</td><td>Everything the browser does, PLUS native plugins where they unlock real capability. Capacitor Haptics (iOS Taptic). <strong>ARKit (iPhone AR) via Swift plugin.</strong> Capacitor&#39;s deep-link / share / app-state APIs.</td><td>The same web bundle as the browser product. The native layer is thin and specific to capabilities the web can&#39;t do.</td></tr></tbody></table><p>Where iPhone gets AR: <strong>the wrapped app only.</strong> iPhone Safari users get the rest of the product (3D + sensory + narration). The wrapped app is the path to real AR on iPhone.</p><p>Where Android gets AR: <strong>everywhere.</strong> Android Chrome (web) and Android wrapped both run the same WebXR code path.</p><hr><h2 id="§goal" tabindex="-1">§goal <a class="header-anchor" href="#§goal" aria-label="Permalink to &quot;§goal&quot;">​</a></h2><p>Ship Immersive Mode on:</p><ul><li><strong>Android web</strong> (Chrome) → WebXR AR on four globe scenes</li><li><strong>Android wrapped</strong> (Capacitor) → same WebXR AR</li><li><strong>iPhone wrapped</strong> (Capacitor + ARKit Swift plugin) → ARKit AR on four globe scenes</li><li><strong>iPhone Safari</strong> → no AR (sensory + narration only — already covered by PRD-017 + PRD-016)</li><li><strong>Desktop browser</strong> → &quot;Exhibit Mode&quot; (cinematic auto-narrated orbits, no AR, chrome-less)</li></ul><p>Four globe scenes: <code>/explore</code> (solar system), <code>/earth</code>, <code>/moon</code>, <code>/mars</code>. <strong>No <code>/fly</code> mission arc in AR for v1</strong> — AU-scale on a tabletop is a hard design problem; deferred to v2. No <code>/iss</code> / <code>/tiangong</code> station-tabletop AR — defer to v2.</p><p><strong>Vision Pro: dropped from v1 scope entirely.</strong> Marko&#39;s call 2026-05-16. The 4 mobile platforms (Android web + Android wrapped + iPhone wrapped + iPhone Safari fallback) are the focus.</p><hr><h2 id="§user-stories" tabindex="-1">§user stories <a class="header-anchor" href="#§user-stories" aria-label="Permalink to &quot;§user stories&quot;">​</a></h2><p><strong>US-1 — Kitchen-table solar system.</strong> User on Android Chrome opens Orrery, navigates to <code>/explore</code>, taps the &quot;Enter AR&quot; button in the nav. Browser requests camera permission. After grant, user taps the floor or table to place the solar system. Saturn appears at scale on the surface; the planets begin their orbits. The Guide voice (auto-played 2 s after placement, per PRD-016) starts narrating. Spatial audio from each planet&#39;s PannerNode follows their physical position on the table. User walks around — planets stay locked to the table; voice stays in centre of their head.</p><p><strong>US-2 — Same experience on iPhone in the wrapped app.</strong> User opens Orrery via the App Store (PRD-015&#39;s wrapped app). Same &quot;Enter AR&quot; button. The ARKit Swift plugin activates instead of WebXR; the plugin exposes the same JS API surface so the Three.js code path doesn&#39;t change. User experience identical to Android.</p><p><strong>US-3 — Exhibit Mode (museum / classroom projector).</strong> Operator opens <code>/?mode=exhibit</code> on a desktop browser, full-screens. The page hides all chrome (nav, footer, HUD), starts a 90-minute cinematic auto-narrated orbit sequence through <code>/explore</code> → <code>/earth</code> → <code>/moon</code> → <code>/mars</code>, ending on a Curator close from PRD-016&#39;s Full Tour. A QR code in the corner offers AR continuation on visitors&#39; devices.</p><p><strong>US-4 — iPhone Safari graceful fallback.</strong> User on iPhone Safari opens Orrery, sees the same nav, but the &quot;Enter AR&quot; button is greyed out with a tooltip: &quot;AR requires the Orrery app on iOS — get it from the App Store [link].&quot; The rest of the product works fully (3D + sensory + narration).</p><p><strong>US-5 — Narrator drives the experience.</strong> Within 2 seconds of AR placement, the Guide voice begins the screen&#39;s episode. Sonification ducks per PRD-017 §M9 audio-bus contract (−34 dB). User listens; planets sing under the voice. Episode ends → sonification restores to full level. User can pause / skip / restart via overlay.</p><hr><h2 id="§must-have-requirements" tabindex="-1">§must-have requirements <a class="header-anchor" href="#§must-have-requirements" aria-label="Permalink to &quot;§must-have requirements&quot;">​</a></h2><table tabindex="0"><thead><tr><th>ID</th><th>Requirement</th></tr></thead><tbody><tr><td><strong>M1</strong></td><td>Single &quot;Enter AR&quot; button in the nav on the 4 globe routes (<code>/explore</code>, <code>/earth</code>, <code>/moon</code>, <code>/mars</code>). Visibility per platform: Android (any browser) shows; iPhone wrapped app shows; iPhone Safari shows greyed-out with tooltip + App Store link; desktop hides.</td></tr><tr><td><strong>M2</strong></td><td><strong>Android (web + wrapped): WebXR AR</strong> via Three.js&#39;s WebXRManager. Requires Three.js WHOLE-CODEBASE UPGRADE (see M14) to a version with reliable hit-test support. Uses ARCore via the browser; no Android-side native plugin.</td></tr><tr><td><strong>M3</strong></td><td><strong>iPhone wrapped: ARKit AR</strong> via a new Capacitor Swift plugin (<code>@orrery/ar-bridge</code>). The plugin wraps ARKit&#39;s <code>ARSession</code> + <code>ARHitTestResult</code> + <code>ARAnchor</code> APIs and exposes them with the SAME JS API surface as WebXR (so the Three.js code path is shared).</td></tr><tr><td><strong>M4</strong></td><td>AR scope = 4 globe scenes for v1: <code>/explore</code>, <code>/earth</code>, <code>/moon</code>, <code>/mars</code>. <code>/fly</code> (mission arc), <code>/iss</code>, <code>/tiangong</code> deferred to v2.</td></tr><tr><td><strong>M5</strong></td><td><strong>Spatial audio.</strong> When AR session starts, the Three.js <code>AudioListener</code> swaps from the flat-screen camera to the XR camera. PRD-017 sonification graphs are reused verbatim — only the listener source changes. Each planet&#39;s PannerNode tracks its 3D world-space position; user walks around and hears Saturn from where Saturn physically is on the table.</td></tr><tr><td><strong>M6</strong></td><td><strong>Narrator auto-play (NE-B).</strong> 2 seconds after AR placement is confirmed (user has tapped the table), the screen&#39;s Guide episode begins. Narrator is centre-panned and spatially fixed 30 cm above and behind the listener&#39;s head (omniscient narrator position — N-B). Sonification ducks to −34 dB per PRD-017 M9.</td></tr><tr><td><strong>M7</strong></td><td><strong>Headphone-aware audio rendering.</strong> <code>navigator.mediaDevices.enumerateDevices()</code> detects connected audio output. Headphones → HRTF spatial audio (<code>PannerNode.panningModel = &#39;HRTF&#39;</code>). Speakers → equal-power stereo. Auto-switch on plug/unplug events.</td></tr><tr><td><strong>M8</strong></td><td><strong>Performance.</strong> 72 fps target on Pixel 6a (representative mid-tier Android), iPhone 12 (representative iPhone), both in AR mode. Simplified starfield in AR (~100 stars vs 2000 in flat-screen). No particles / comets / orbit trails in AR.</td></tr><tr><td><strong>M9</strong></td><td><strong>Bundle isolation.</strong> XR module (Three.js XR scene builders + AR control overlay) is a Vite lazy chunk, loaded only when user taps &quot;Enter AR&quot;. &lt;50 KB minified gzipped. Exhibit Mode is a separate lazy chunk, &lt;20 KB. Zero impact on the flat-screen bundle.</td></tr><tr><td><strong>M10</strong></td><td><strong>AR session storage = in-memory only.</strong> Per ADR-057, no localStorage. AR placement state (anchor position, narrator playback position) is runtime-only; exiting the AR session resets state. NO sessionStorage either — the original draft proposed sessionStorage; replaced with in-memory state per CLAUDE.md / ADR-057.</td></tr><tr><td><strong>M11</strong></td><td><strong>Exhibit Mode (M-B chrome-less).</strong> <code>?mode=exhibit</code> URL param. Hides all chrome (nav, footer, HUD overlays). Auto-starts a cinematic playlist: 22 min <code>/explore</code> (Curator + Kepler chord + planet tour) → 18 min <code>/earth</code> (Earth orbit regime overview) → 22 min <code>/moon</code> (terminator + far-side + Apollo sites) → 18 min <code>/mars</code> (rover sites + signal-delay moment) → 10 min Curator close. ~90 min total. Loops. QR code static-corner overlay pointing to the AR experience on visitor&#39;s device.</td></tr><tr><td><strong>M12</strong></td><td><strong>iPhone Safari fallback messaging.</strong> &quot;Enter AR&quot; button on iPhone Safari is visually distinct (greyed-out + small &quot;iOS app&quot; badge). Tap opens a non-modal sheet: &quot;Real AR on iPhone needs the Orrery app. [Download from App Store]&quot; + &quot;Or continue with the sensory experience (tilt + sound + haptics).&quot; Honest framing; not a dead-end.</td></tr><tr><td><strong>M13</strong></td><td><strong><code>@capacitor/haptics</code> integration in AR.</strong> AR-specific haptic events (per RFC-021 §haptics-in-AR): anchor placement confirmed → light pulse; narrator-section transition → light pulse; episode end → triple light pulse. Reuses the patterns already specified in PRD-017 RFC-020 §5.2.</td></tr><tr><td><strong>M14</strong></td><td><strong>Three.js WHOLE-CODEBASE UPGRADE — v1 prerequisite.</strong> All 7 existing 3D scenes migrate from r128 to current Three.js (likely r170+) before Immersive Mode work begins. This is a meaningful undertaking — see §dependencies for scope estimate. Justified by: (a) WebXR hit-test reliability requires modern Three.js, (b) keeping two Three.js versions in the build is a maintenance trap.</td></tr><tr><td><strong>M15</strong></td><td><strong>ARKit Swift plugin scope.</strong> <code>@orrery/ar-bridge</code> Capacitor plugin (Swift package) exposes 6 methods: <code>requestSession()</code> / <code>endSession()</code> / <code>hitTest(x, y)</code> / <code>addAnchor(anchor)</code> / <code>removeAnchor(anchor)</code> / <code>getCameraPose()</code>. Plus 3 events emitted to JS: <code>session-started</code>, <code>frame</code> (per RAF with camera pose), <code>session-ended</code>. ~600 lines Swift. Lives in the Capacitor <code>ios/</code> directory; no separate iOS repo.</td></tr><tr><td><strong>M16</strong></td><td><strong>AR camera passthrough video respects user privacy.</strong> Camera frame data is NEVER stored, transmitted, or logged. Only spatial-tracking data (camera pose + anchor positions) is used by JS. Documented in the privacy policy + the AR permission grant UI (&quot;Orrery uses your camera to place the solar system in your room. Camera frames are processed on your device and never sent anywhere.&quot;).</td></tr></tbody></table><hr><h2 id="§should-have-requirements" tabindex="-1">§should-have requirements <a class="header-anchor" href="#§should-have-requirements" aria-label="Permalink to &quot;§should-have requirements&quot;">​</a></h2><table tabindex="0"><thead><tr><th>ID</th><th>Requirement</th></tr></thead><tbody><tr><td><strong>S1</strong></td><td>Single-tap &quot;Re-place&quot; gesture during an AR session: user taps the table again to re-anchor the scene.</td></tr><tr><td><strong>S2</strong></td><td>Visual on-boarding overlay first time the user enters AR: 3-second hint showing the &quot;tap surface to place&quot; gesture, then dismisses on tap. Once per session (in-memory; no persistence).</td></tr><tr><td><strong>S3</strong></td><td>&quot;Exit AR&quot; button visible in the AR session UI (top-right corner of overlay), 44×44 px.</td></tr><tr><td><strong>S4</strong></td><td>Exhibit Mode&#39;s QR code link is configurable per deployment (URL param <code>?qr=&lt;shortlink&gt;</code>) — museum operators can point it to their landing page.</td></tr><tr><td><strong>S5</strong></td><td>Per-platform telemetry in the analytics pipeline (PRD-015 already wires the global click delegation): <code>ar-session-start</code> / <code>ar-session-end</code> / <code>ar-error</code> events with platform context (<code>&#39;android-web&#39;</code> / <code>&#39;android-wrapped&#39;</code> / <code>&#39;iphone-wrapped&#39;</code>). Helps prioritise v2 work.</td></tr></tbody></table><hr><h2 id="§will-not-have-v1" tabindex="-1">§will-not-have (v1) <a class="header-anchor" href="#§will-not-have-v1" aria-label="Permalink to &quot;§will-not-have (v1)&quot;">​</a></h2><ul><li><strong>Vision Pro support.</strong> Dropped from v1 scope (Marko 2026-05-16). Focus is mobile (Android + iPhone).</li><li><strong><code>/fly</code> mission arc in AR.</strong> AU-scale on a tabletop is a hard design problem; deferred to v2.</li><li><strong><code>/iss</code> / <code>/tiangong</code> station-tabletop AR.</strong> Defer to v2.</li><li><strong>AR on iPhone Safari.</strong> Apple has not shipped WebXR. Honest framing in M12 fallback.</li><li><strong>AR occlusion (hands blocking planets).</strong> Requires ARCore Depth API + ARKit Scene Geometry — both v2.</li><li><strong>Anchor persistence across sessions.</strong> Put phone down, pick up, anchor still there. Requires cloud anchors or persisted ARCore state; v2.</li><li><strong>Multi-user shared AR.</strong> Two phones, same scene. Requires Google Cloud Anchors or ARKit collaborative sessions; v2.</li><li><strong>Script-aware narrator-sonification semantic ducking.</strong> v1 uses amplitude-based ducking only (PRD-017 M9). Semantic tags (&quot;duck during equation explanation but not during transition&quot;) deferred to v1.x.</li><li><strong>Exhibit Mode synced multi-screen (multi-projector wall).</strong> WebSocket-coordinated sync between 2+ projectors. v2.</li><li><strong>Vision Pro gaze + pinch UX adaptation.</strong> Dropped along with Vision Pro scope.</li></ul><hr><h2 id="§success-criteria" tabindex="-1">§success-criteria <a class="header-anchor" href="#§success-criteria" aria-label="Permalink to &quot;§success-criteria&quot;">​</a></h2><p><strong>Editorial:</strong></p><ol><li>A first-time AR user on Android Chrome at <code>/explore</code> taps &quot;Enter AR&quot;, places the solar system, and within 2 seconds the Guide narration starts. The first 10 minutes are uninterrupted (no UX breakdowns; no 3D drift; no audio glitch).</li><li>iPhone wrapped app delivers IDENTICAL editorial experience to Android Chrome (per US-2). Cross-platform user study (Marko + 2 reviewers, one Android one iPhone) confirms parity.</li><li>Exhibit Mode runs unattended for 8+ hours without crash on a desktop browser (manual test).</li></ol><p><strong>Technical:</strong> 4. 72 fps held on Pixel 6a + iPhone 12 in AR mode for full 90 s sessions (Lighthouse mobile + Chrome DevTools / Xcode Instruments profiling). 5. XR + Exhibit chunks total &lt; 70 KB minified gzipped; zero impact on flat-screen bundle size. 6. Three.js whole-codebase upgrade lands with zero visual regression on the 7 existing 3D scenes (validated via the visual regression baselines from <code>tests/e2e/visual.spec.ts</code> + manual review of each scene). 7. ARKit Swift plugin builds clean on Xcode 16+; no warnings; passes App Store review.</p><p><strong>Operational:</strong> 8. iPhone Safari users see the M12 fallback messaging on first AR-button tap (no broken-button confusion). 9. Camera permission request UX is honest about what data is used (M16).</p><hr><h2 id="§dependencies" tabindex="-1">§dependencies <a class="header-anchor" href="#§dependencies" aria-label="Permalink to &quot;§dependencies&quot;">​</a></h2><p><strong>Must ship first (entire stack):</strong></p><ul><li>PRD-015 / RFC-018 — Capacitor mobile wrapper (Android-first; iPhone follows). Without it, no wrapped app exists.</li><li>PRD-016 / RFC-019 — Audio narration. Without it, no Guide voice to auto-play.</li><li>PRD-017 / RFC-020 — Sensory layer. Provides the sonification graph that Immersive Mode reuses + audio-bus ducking contract.</li><li>PRD-018 / RFC-022 — Image Pipeline v2 (loose dependency — not strictly required, but the smart-crop variants improve AR texture quality).</li></ul><p><strong>Three.js upgrade — v1 prerequisite (NOT a v1 feature):</strong></p><ul><li>All 7 existing 3D scenes (<code>/explore</code>, <code>/fly</code> heliocentric, <code>/fly</code> cislunar, <code>/earth</code>, <code>/moon</code>, <code>/mars</code>, <code>/iss</code>, <code>/tiangong</code>) migrate from r128 to current Three.js (likely r170+).</li><li>Estimated 4-6 weeks engineering work (audit breaking changes → scene-by-scene migration → visual regression sweep → fix-up).</li><li>Risk: regressions across the existing 3D corpus. Mitigation: aggressive use of <code>tests/e2e/visual.spec.ts</code> baselines + the audit-report pattern from PRD-018.</li></ul><p><strong>ARKit Swift plugin — v1 prerequisite:</strong></p><ul><li>New <code>@orrery/ar-bridge</code> Capacitor plugin, ~600 lines Swift.</li><li>~3-4 weeks Swift + Capacitor plugin development.</li><li>Owned by Marko (per PRD-015 §iOS code-signing — Marko owns the iOS path).</li></ul><p><strong>ADR-057:</strong> Strict — no localStorage, no sessionStorage. AR session state is in-memory only.</p><hr><h2 id="§resolved-decisions" tabindex="-1">§resolved decisions <a class="header-anchor" href="#§resolved-decisions" aria-label="Permalink to &quot;§resolved decisions&quot;">​</a></h2><p><em>Resolved 2026-05-16 in conversation with Marko.</em></p><ol><li><strong>Three.js — RESOLVED: Upgrade across the whole codebase</strong> (NOT just the XR module). All 7 existing 3D scenes migrate from r128 to current. Single Three.js version in the build. v1 prerequisite, not a v1 deliverable.</li><li><strong>Narrator — RESOLVED: Bake in from v1.</strong> Immersive Mode ships only after PRD-016 audio lands (v0.9). Guide episode auto-plays 2 s after AR placement.</li><li><strong>AR scope — RESOLVED: 4 globe scenes only</strong> (<code>/explore</code>, <code>/earth</code>, <code>/moon</code>, <code>/mars</code>). <code>/fly</code> mission arc deferred to v2; <code>/iss</code> + <code>/tiangong</code> deferred.</li><li><strong>iPhone AR path — RESOLVED: Path A — Capacitor + ARKit Swift plugin</strong> (<code>@orrery/ar-bridge</code>). The only way to ship real AR on iPhone since Apple has not shipped WebXR.</li><li><strong>Web-vs-app split — RESOLVED: Web product stays web-only; mobile app is allowed native power.</strong> &quot;Browser product&quot; is web-pure; &quot;mobile app product&quot; can use Capacitor plugins (including ARKit) where they unlock things the web can&#39;t. Evolves PRD-015&#39;s framing; codified in §architectural-axis.</li><li><strong>Vision Pro — RESOLVED: Dropped from v1 entirely.</strong> Focus on mobile (Android + iPhone). Vision Pro is not a v1 audience.</li><li><strong>AR session storage — RESOLVED: In-memory only.</strong> Original draft proposed sessionStorage; corrected per ADR-057 to runtime-only state.</li><li><strong>Headphone-aware audio rendering — RESOLVED: Auto-detect via <code>navigator.mediaDevices.enumerateDevices()</code></strong> → HRTF on headphones, equal-power stereo on speakers (M7).</li></ol><hr><h2 id="§open-questions" tabindex="-1">§open questions <a class="header-anchor" href="#§open-questions" aria-label="Permalink to &quot;§open questions&quot;">​</a></h2><ol start="9"><li><strong>ARKit Swift plugin maintenance burden.</strong> ~600 lines of Swift + Apple&#39;s ARKit API evolution. Who owns it long-term? Marko (per PRD-015 iOS signing) is the default — confirm acceptable maintenance commitment.</li><li><strong>Three.js upgrade risk envelope.</strong> Estimated 4-6 weeks. Open: how aggressively to validate? Visual regression baselines (tests/e2e/visual.spec.ts) cover ~6 surfaces; the 7 3D scenes are not in that suite (canvas regressions are flaky). Manual review pass required. Operational, not architectural.</li><li><strong>AR onboarding UX iteration.</strong> S2 first-time hint may need 2-3 design iterations before launch. Implementation-time.</li><li><strong>Exhibit Mode QR code → AR continuation handshake.</strong> Operator deploys Exhibit Mode on a kiosk; visitor scans QR; the visitor&#39;s phone opens the AR experience deep-linked to the current scene. Implementation: <code>orrery://?audio=...&amp;mode=ar&amp;scene=explore</code> deep-link (per RFC-018 §7). Refine at impl time.</li><li><strong>iPhone wrapped app — TestFlight vs direct App Store path.</strong> Marko&#39;s Apple Dev account (PRD-015) handles both. Open: ship to TestFlight first for 2 weeks before public App Store? Recommend yes.</li></ol><hr><p><em>PRD-019 · Orrery · Immersive Mode · Drafted 2026-05-16 · Closes-into-RFC-021</em></p>',68)])])}const g=t(s,[["render",a]]);export{u as __pageData,g as default};
